keyword = '파이썬'

with open('search.txt', 'r', encoding='utf-8') as f:
    lines = f.readlines()

for line in lines:
    if keyword in line:
        print(line.strip())

config = {}

with open('config.txt', 'r', encoding='utf-8') as f:
    for line in f:
        line = line.strip()
        if not line or line.startswith('#'):
            continue
        key, value = line.split('=', 1)
        config[key.strip()] = value.strip()
